    ('BUS-W 579', 'EXPERIMENTAL COURSE IN MANAGEMENT', '34478', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 9:00 AM–12:00 PM', 'CG 1022 CG 1022', 'Richard Ash', 16, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This seven week course focuses upon a new topic in Management relevant to management decision making and appraisal of the external environment faced by organizations. Learning occurs through lecture, case discussion, problem solving, group projects, or completion of exercises that further the knowledge and skills of MBA students enrolled in the course.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 155', 'TOPICS IN BUSINESS', '35156', 'Closed', NULL, 'WB WEB', 'Maggie Sperry', 0, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'X155 is a freshman-level experimental course. The purpose of this course is to serve as a venue for innovation in subject matter coverage and pedagogy.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 170', 'HOW BUSINESS WORKS', '9049', 'Class Status', 'Intersession', 'WB WEB', 'Bryce Bow, Kent Rerko, Jeanette Heidewald, Gerry Hays, Joseph Fitter, G Arave, John Talbott', 402, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will focus on three elements of importance. It will address real and contemporary business organizations/products/issues; it is decision-oriented rather than just a descriptive course; and, the course will emphasize integration and how the various functions of business relate to one another.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-X 180', 'JLLC COMMUNITY DEVELOPMENT', '14031', 'Closed', 'M Monday 1:55 PM–2:45 PM', 'MN C010', 'Wendi Tai', 0, NULL, 'Lecture', '1', 'MCNUTT CENTRAL', ARRAY[]::TEXT[], 'BUS-X 180 is a discussion-based course that gives first-year students an opportunity to tie together three aspects of a student''s development (personal, academic, and professional). Students will set personal, academic, and professional goals while gaining the confidence and interpersonal skills necessary to connect witih peers, professors, and business professionals.', ARRAY[]::TEXT[], NULL),
