    ('BUS-X 403', 'THE CONSULTING INDUSTRY', '5526', 'Closed', 'Intersession', NULL, 'Joel Rubin', 0, NULL, 'Practicum', '1.5', NULL, ARRAY[]::TEXT[], 'This course is designed to familiarize the student with the consulting industry. That includes providing a framework for distinguishing among consulting firms and affording the student opportunties to compare and contrast consulting firms.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 404', 'STRUCTURED THINKING & INTERPERSONAL ASPECTS OF CONSULTING', '3584', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 3059', 'Joel Rubin', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is designed to develop your analytic and communications skills and help you succeed in consulting-type case interviews, to build on the skills that you developed in J420, and to develop the interpersonal skills that are crucial to longer-term success as a consultant.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 419', 'LIFE SCIENCE INDUSTRY FROM RESEARCH TO PATIENT', '34834', 'Closed', 'Tu Tuesday 6:15 PM–9:15 PM', 'CG 1040', 'George Telthorst', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course introduces students to all the parts of the industry including the players and their challenges in basic science, medical devices, pharmaceuticals, generics, biotech, distributors, health care providers, insurers, venture capitalists, etc. It also defines the concept of value chain which describes how these players interrelate in the production of life science outcomes.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 496', 'SUPERVISED INDEPENDENT HONORS RESEARCH', '1228', 'Closed', NULL, NULL, 'Staff', 0, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'For students in School of Business Honors Program.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 501', 'INFORMATION SYSTEMS CORE', '37135', 'Closed', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 8:00 AM–2:00 PM', 'CG 1032 CG 1032', 'Bipin Prabhakar', 0, NULL, 'Lecture', '15', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The Core is designed to provide a foundation and breadth of knowledge and skills necessary for advancement in major organizations worldwide or to successfully start and grow a business of your own. Modules focus on helping you develop tools and concepts necessary to solve complex and unstructured business IT problems.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 501', 'INFORMATION SYSTEMS CORE', '37136', 'Closed', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 8:00 AM–2:00 PM', 'CG 1014 CG 1014', 'Bipin Prabhakar', 0, NULL, 'Lecture', '15', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The Core is designed to provide a foundation and breadth of knowledge and skills necessary for advancement in major organizations worldwide or to successfully start and grow a business of your own. Modules focus on helping you develop tools and concepts necessary to solve complex and unstructured business IT problems.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 505', 'LEADERSHIP, PROFESSIONAL AND CAREER DEVELOPMENT', '3099', 'Class Status', NULL, NULL, 'John Hill', 12, NULL, 'Lecture', '1.5', NULL, ARRAY[]::TEXT[], 'The focus of this course is on developing students as business professionals. Topics include: Identifying and leveraging one''s personal leadership style, maintaining ethical standards, writing resumes, managing and practicing interviews, leading in diverse environments, communicating effectively, networking for career success, and conducting research to capitalize on job opportunities.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 515', 'ACADEMY INTENSIVE WEEK #1', '3175', 'Class Status', 'Kelley Academy Week 1', NULL, 'Sena Durguner', 17, NULL, 'Lecture', '1.5', NULL, ARRAY[]::TEXT[], 'In this intensive course, students focus on a specialized industry or business area. Various pedagogical techniques are used including lectures, case discussions, exercises, trips, workshops, speakers, and projects. Students select from a list of areas including consumer marketing, entrepreneurship, healthcare, investment management, investment consulting, sports and entertainment and others.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 515', 'ACADEMY INTENSIVE WEEK #1', '3176', 'Class Status', 'Kelley Academy Week 1', NULL, 'Matthew O Hern', 11, NULL, 'Lecture', '1.5', NULL, ARRAY[]::TEXT[], 'In this intensive course, students focus on a specialized industry or business area. Various pedagogical techniques are used including lectures, case discussions, exercises, trips, workshops, speakers, and projects. Students select from a list of areas including consumer marketing, entrepreneurship, healthcare, investment management, investment consulting, sports and entertainment and others.', ARRAY[]::TEXT[], NULL),
