    ('BUS-X 519', 'BUSINESS OF LIFE SCIENCES: VALUE CHAIN', '8607', 'Class Status', 'Tu Tuesday 6:15 PM–9:15 PM', 'CG 1040', 'George Telthorst', 3, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course introduces students to all the parts of the industry including the players and their challenges in basic science, medical devices, pharmaceuticals, generics, biotech, distributors, health care providers, insurers, venture capitalists, etc. It also defines the concept of value chain which describes how these players interrelate in the production of life science outcomes.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 520', 'WASHINGTON CAMPUS PROGRAM', '6714', 'Closed', 'Intersession', NULL, 'Emily Stern', 0, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], 'Intensive summer study of the process of the federal government, its environment, and the ways by which federal policies are developed. Subjects include: policy development in the executive branch, government regulation, lobbying activities, and domestic and international economic policy issues.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 530', 'OVERSEAS BUSINESS STUDY:', '36783', 'Class Status', 'Kelley Second Seven Week', NULL, 'Emily Stern', 4, NULL, 'Independent Study', '0–15', NULL, ARRAY[]::TEXT[], 'Participation in an overseas study opportunity sponsored by the Graduate School of Business. The opportunity may take place during the fall, spring or summer semesters after the first year of the program in a number of overseas locations.', ARRAY[]::TEXT[], NULL),
    ('BUS-X 540', 'INTERNATIONAL PRACTICUM', '12626', 'Class Status', NULL, NULL, 'Gretchen Handlos', 9, NULL, 'Practicum', '0', NULL, ARRAY[]::TEXT[], 'As part of their graduate study in the United States, international students are encouraged to undertake a practicum with a U.S. based business. Enrollment in this course is limited to Non-U.S. citizens. The practicum or internship experience must be approved in advance and a written evaluation of the experience is required.', ARRAY[]::TEXT[], NULL),
