    ('BUS-X 541', 'MBA FOUNDATIONS CORE 1', '12972', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 9:00 AM–5:05 PM', 'CG 1050', 'John Hill', 8, NULL, 'Lecture', '7.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'MBA Foundations Core 1 introduces students to the fundamentals of business including statistics, operations management, business communication, financial accounting and critical thinking.', ARRAY['Class uses IU eTexts'], NULL),
