    ('BUS-Z 340', 'INTRODUCTION TO HUMAN RESOURCES', '4307', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'HH 1038', 'Samanta Fonseca', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Nature of human resource development and utilization in American society and organizations; government programs and policies, labor force statistics, organizational personnel departments, personnel planning, forecasting, selection, training, development, and integration of government and organizational human resource programs.', ARRAY['Class uses IU eTexts'], NULL),
