    ('BUS-Z 404', 'EFFECTIVE NEGOTIATIONS', '1234', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 3057', 'Richard Ash', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Negotiation, art and science of securing agreements between two or more parties who are interdependent and need each other to meet professional or personal goals. You can think about negotiation as a decision-making process by which two or more people try to come to agreement on how to allocate resources.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-Z 404', 'EFFECTIVE NEGOTIATIONS', '12683', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 2049', 'Richard Ash', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Negotiation, art and science of securing agreements between two or more parties who are interdependent and need each other to meet professional or personal goals. You can think about negotiation as a decision-making process by which two or more people try to come to agreement on how to allocate resources.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-Z 447', 'LEADERSHIP, TEAMWORK AND DIVERSITY', '4306', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 3006', 'Anna Lennard', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course uses a "matrix approach" to provide an integrated experience for the student. Ultimately, this course aims to strengthen students'' leadership potential, their ability to be an effective team member of a high performing team, and to understand, respect, and value diversity.', ARRAY[]::TEXT[], NULL),
    ('BUS-Z 447', 'LEADERSHIP, TEAMWORK AND DIVERSITY', '12684', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'HH 3006', 'Anna Lennard', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course uses a "matrix approach" to provide an integrated experience for the student. Ultimately, this course aims to strengthen students'' leadership potential, their ability to be an effective team member of a high performing team, and to understand, respect, and value diversity.', ARRAY[]::TEXT[], NULL),
    ('BUS-Z 447', 'LEADERSHIP, TEAMWORK AND DIVERSITY', '29838', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3057', 'Anna Lennard', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course uses a "matrix approach" to provide an integrated experience for the student. Ultimately, this course aims to strengthen students'' leadership potential, their ability to be an effective team member of a high performing team, and to understand, respect, and value diversity.', ARRAY[]::TEXT[], NULL),
    ('BUS-Z 494', 'HERMAN B WELLS HONOR SEMINAR IN LEADERSHIP', '4393', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'AC C112', 'Brian Hathaway', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course is for students with high scholastic ability and promise of developing leadership qualities exemplified by Herman B. Wells. Topics may include leadership, globalization, and e-commerce.', ARRAY[]::TEXT[], NULL),
    ('BUS-Z 504', 'FOUNDATIONS OF ORGANIZATIONAL BEHAVIOR AND HUMAN RESOURCE MANAGEMENT', '35092', 'Class Status', 'TuTh Tuesday, Thursday 9:00 AM–12:00 PM', 'CG 2077', 'Michael DeShano', 15, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is designed to provide a comprehensive overview of the fundamental concepts and theories that are central to effective management and becoming an effective manager.', ARRAY[]::TEXT[], NULL),
    ('BUS-Z 525', 'FOUNDATIONS OF LEADERSHIP', '14995', 'Class Status', 'Th Thursday 1:10 PM–4:35 PM', 'CG 2061', 'Justin Delaney', 3, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The objective of this class is to enhance your understanding of what makes leaders effective in organizational settings by: (a) exploring the criteria of leadership effectiveness, (b) identifying those behaviors that are found to be most important for enhancing leadership effectiveness, and (c) exploring how to improve your leadership "style".', ARRAY[]::TEXT[], NULL),
    ('BUS-Z 531', 'STRATEGIC HUMAN RESOURCE MANAGEMENT', '14529', 'Class Status', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 2063', 'Tiffany Lemons', 14, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Strategic HR uses traditional tools - recruitment, selection, performance management, compensation, training/development to ensure employees are sources of competitive advantage for their organizations. This courses focuses on the actions and outcomes that execute the firm''s strategy, motivate strategic behavior by employees, and provide the firm with talent to support growth.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-Z 565', 'MBA LEADERSHIP ACADEMY - LEADER AS COACH - INDIVIDUAL COACHING FOUNDATIONS', '14654', 'Class Status', NULL, 'MTuW Monday, Tuesday, Wednesday 9:00 AM–5:00 PM F Friday 9:00 AM–12:00 PM Regular Academic Session 8/25/2025–12/19/2025', 'CG 2063 CG 2063', NULL, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The fall semester of the MBA Leadership Academy develops and improves student leadership skills. Coaching is a relevant leadership tool as organizations continue to move towards a inclusive approach to organizational development. Coaching skills are a part of Transformational Leadership and Servant Leadership, which will be covered throughout the course.', ARRAY[]::TEXT[], NULL),
    ('CEUS-G 599', 'THESIS RESEARCH', '3117', 'Class Status', NULL, NULL, 'Oner Ozcelik', 1, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('CEUS-G 901', 'ADVANCED RESEARCH', '1235', 'Class Status', NULL, NULL, 'Oner Ozcelik', 6, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('CEUS-G 901', 'ADVANCED RESEARCH', '6982', 'Class Status', NULL, NULL, 'Oner Ozcelik', 2, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 110', 'CENTRAL ASIA: CULTURES AND CUSTOMS', '37185', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–8:00 PM', 'GA 0009', 'Gulnisa Nazarova', 10, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to Central Asia, including Xinjiang and Mongolia, and Central Asian peoples. Examines the fabled "Silk Road" and the diverse cultures, societies, and life-ways of this region: herders, farmers, caravan traders, and city-dwellers. Most of the population is Muslim and Turkic-speaking but other religions and languages are represented as well.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
