    ('CEUS-R 199', 'INTRODUCTORY TOPICS IN CENTRAL EURASIAN STUDIES', '37567', 'Class Status', 'MW Monday, Wednesday 1:55 PM–4:25 PM', 'WB WEB', 'Malik Hodjaev', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Variable title course for introductory topics in Central Eurasian studies.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 290', 'INTRODUCTION TO CENTRAL ASIA, MONGOLIA, AND TIBET', '9350', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'GA 1122', 'Michael Brose', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Central Asia, Mongolia, and Tibet have a unique legacy in the world today: nomads, Silk Road, Islam, Buddhism, Russo-Chinese rivalry, Communism, and resistance. This course will provide a broad overview of trends and issues in this crossroads of cultures and civilizations through a combination of lectures, discussions, and guest presentations.', ARRAY['IUB GenEd S&H credit
