    ('CEUS-R 318', 'LABOR AND MIGRATION IN CENTRAL ASIA', '32581', 'Closed', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'AD A152', 'Marianne Kamp', 0, NULL, 'Lecture', '3', 'AUDITORIUM', ARRAY[]::TEXT[], 'Traces migration flows in Soviet and contemporary Central Asia, asking questions about labor economics, gender, culture and ethnicity in labor migration. Focuses on shifts from formal to informal labor.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
