    ('CEUS-R 349', 'TOPICS IN HUNGARIAN STUDIES', '33734', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WH 108', 'Gergely Rajnai', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Variable title course for topics in Hungarian studies.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 349', 'TOPICS IN HUNGARIAN STUDIES', '33777', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 214', 'Reka Benczes', 16, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Variable title course for topics in Hungarian studies.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 349', 'TOPICS IN HUNGARIAN STUDIES', '33778', 'Class Status', 'TuTh Tuesday, Thursday 1:00 PM–2:15 PM', 'BH 315', 'Reka Benczes', 15, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Variable title course for topics in Hungarian studies.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 349', 'TOPICS IN HUNGARIAN STUDIES', '37321', 'Class Status', 'MW Monday, Wednesday 12:45 PM–3:15 PM', 'ED 3004', 'Laszlo Borhi', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Variable title course for topics in Hungarian studies.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 349', 'TOPICS IN HUNGARIAN STUDIES', '37490', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–3:15 PM', 'SY 0013', 'Gergely Rajnai', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Variable title course for topics in Hungarian studies.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 354', 'PERSIAN LITERATURE IN TRANSLATION', '37127', 'Class Status', 'MW Monday, Wednesday 4:20 PM–6:50 PM', 'BH 141', 'Narges Nematollahi', 18, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study and analysis of selected readings from Persian literature in English translation. May concentrate on a particular theme, period, or author. Special attention paid to the historical and cultural contexts of the works, as well as problems in translation, critical analysis, and interpretation.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CEUS-R 355', 'FOREIGN POLICIES, ALLIANCES, AND CONFLICTS: IRAN IN THE CONTEMPORARY PERSIAN GULF', '29597', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AC C112', 'Feisal Istrabadi', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Examines the rise of the Islamic Republic of Iran, the regional and superpower responses, and the implications for current and near-term US policy.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('CEUS-R 386', 'ISLAM, ISLAMISM, AND MODERNITY IN TURKEY', '11845', 'Class Status', 'MW Monday, Wednesday 4:20 PM–6:50 PM', 'BH 135', 'Kemal Silay', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores the complex relationship between Islam and politics, and Islamism''s predicament with modernity and democracy. Although it concentrates on Turkey and its Ottoman past, a comparative approach examines developments throughout the Muslim Middle East and other parts of the world affected by the phenomena of political Islam and jihadist discourses and activities.', ARRAY['COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('CEUS-R 393', 'THE MONGOL CENTURY', '33362', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GA 0013', 'Michael Brose', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'In-depth exploration of Chinggis Khan''s Mongol Empire from its origins in the twelfth century in the continent-wide breakdown of the 1330s-1370s. Primary sources (Mongolian, Chinese, Middle Eastern, and European) in translation, including many of the medieval era''s greatest histories and travelogues.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('CEUS-R 417', 'ORAL HISTORY IN EURASIA: RESEARCH METHODS AND INTERNATIONAL EXPERIENCE', '29462', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'GA 0007', 'Marianne Kamp', 9, NULL, 'Methods Course', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Focuses on developing an oral history research project concerning a cultural/historical theme in Central Eurasia. Includes instruction and practice in the methods and best practices of oral history, such as conducting interviews and analyzing them as sources for understanding research themes. Sometimes includes an international learning component.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 492', 'LANGUAGE AND SOCIETY IN CENTRAL EURASIA', '29765', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 112', 'Kathryn Graber', 1, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This seminar explores how language is used to accomplish economic, political, and sociocultural ends in Central Eurasia. Topics covered include multilingualism; regional ethnolinguistic categories; the relationship between language policy and nationalities policy; gendered language; code choice in interactions; the politics of translation; poetics; standardization; and language shift, endangerment, and revitalization.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('CEUS-R 493', 'THEORIZING CENTRAL EURASIA: THE PROBLEMS OF NATIONALISM', '29451', 'Class Status', 'F Friday 12:45 PM–3:15 PM', 'LH 120', 'Gardner Bovingdon', 14, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'An introduction to nationalism in Central Eurasia, and to its key works and questions. How are nations related? Are nations imagined and invented or ancient and enduring? Are nationalism, communism, and religiosity necessarily opposed? Are indigenous nationalisms more authentic than "official nationalisms"? Is Central Eurasian nationalism a "derivative discourse," imported from somewhere?', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('CEUS-R 509', 'TOPICS IN BALTIC-FINNISH STUDIES', '15315', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'GA 0003', 'Piibi-Kai Kivik', 14, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Topics in Baltic-Finnish Studies is used for new classes in Baltic-Finnish studies, aimed at MA and early Ph.D students and/or upper division undergraduates. Such classes are typically taught by a mix of lecture and discussion.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 509', 'TOPICS IN BALTIC-FINNISH STUDIES', '36247', 'Class Status', 'MW Monday, Wednesday 3:10 PM–5:40 PM', 'SB 231', 'Juho Korhonen', 21, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Topics in Baltic-Finnish Studies is used for new classes in Baltic-Finnish studies, aimed at MA and early Ph.D students and/or upper division undergraduates. Such classes are typically taught by a mix of lecture and discussion.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 509', 'TOPICS IN BALTIC-FINNISH STUDIES', '37087', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'WH 008', 'Petro Kuzyk', 16, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Topics in Baltic-Finnish Studies is used for new classes in Baltic-Finnish studies, aimed at MA and early Ph.D students and/or upper division undergraduates. Such classes are typically taught by a mix of lecture and discussion.', ARRAY[]::TEXT[], NULL),
