    ('CEUS-R 559', 'TOPICS IN IRANIAN STUDIES', '29598', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'AC C112', 'Feisal Istrabadi', 2, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'Topics in Iranian Studies is used for new classes in Iranian studies, aimed at M.A. and early Ph.D. students and/or upper division undergraduates. Such classes are typically taught by a mix of lecture and discussion.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 586', 'ISLAM, ISLAMISM, AND MODERNITY IN TURKEY', '11846', 'Class Status', 'MW Monday, Wednesday 4:20 PM–6:50 PM', 'BH 135', 'Kemal Silay', 5, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Explores complex relationship between Islam and politics, and Islamism''s predicament with modernity and democracy. Although it concentrates on Turkey and its Ottoman past, a comparative approach examines developments throughout Muslim Middle East and other parts of the world affected by the phenomena of political Islam and jihadist discourses and activities.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 600', 'ADVANCED READINGS IN BALTIC-FINNISH STUDIES', '1257', 'Class Status', NULL, NULL, 'Piibi-Kai Kivik', 2, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Baltic-Finnish studies. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 610', 'ADVANCED READINGS IN CENTRAL ASIAN STUDIES', '4509', 'Class Status', NULL, NULL, 'Marianne Kamp', 4, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Central Asian studies. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 617', 'ORAL HISTORY IN EURASIA: RESEARCH METHODS AND INTERNATIONAL EXPERIENCE', '29463', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'GA 0007', 'Marianne Kamp', 9, NULL, 'Methods Course', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Class members participate in an oral history research project concerning a cultural/historical theme in Eurasia, conduct interviews, and analyze them as sources for understanding research themes. This course includes an international experience component.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 640', 'ADVANCED READINGS IN HUNGARIAN STUDIES', '4512', 'Class Status', NULL, NULL, 'Valeria Varga', 1, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Hungarian studies. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 670', 'ADVANCED READINGS IN TIBETAN STUDIES', '4514', 'Class Status', NULL, NULL, 'Gedun Rabsal', 1, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Tibetan studies. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 680', 'ADVANCED READINGS IN TURKISH STUDIES', '4515', 'Class Status', NULL, NULL, 'Oner Ozcelik', 1, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Turkish studies. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 690', 'ADVANCED READINGS IN CENTRAL EURASIAN STUDIES', '13161', 'Class Status', NULL, NULL, 'Oner Ozcelik', 2, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Central Eurasian studies that cover multiple CEUS areas or do not fit comfortably in any specific area. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 690', 'ADVANCED READINGS IN CENTRAL EURASIAN STUDIES', '4516', 'Class Status', NULL, NULL, 'Oner Ozcelik', 10, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Central Eurasian studies that cover multiple CEUS areas or do not fit comfortably in any specific area. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 690', 'ADVANCED READINGS IN CENTRAL EURASIAN STUDIES', '37037', 'Closed', NULL, NULL, 'Kathryn Graber', 0, NULL, 'Lecture', '1–6', NULL, ARRAY[]::TEXT[], 'This course number is for tutorials in advanced topics in Central Eurasian studies that cover multiple CEUS areas or do not fit comfortably in any specific area. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic or some combination thereof.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 691', 'CEUS MA THESIS RESEARCH', '1258', 'Class Status', NULL, NULL, 'Oner Ozcelik', 4, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'This course is required for all CEUS graduate students seeking a Master''s Degree who have not written a thesis for a previous M.A. degree. It is normally taken during the fourth or fifth semester of a student''s enrollment concurrently with writing a thesis.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 692', 'LANGUAGE AND SOCIETY IN CENTRAL EURASIA', '29766', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'LH 112', 'Kathryn Graber', 3, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This seminar explores how language is used to accomplish economic, political, and sociocultural ends in Central Eurasia. Topics covered include multilingualism; regional ethnolinguistic categories; the relationship between language policy and nationalities policy; gendered language; code choice in interactions; the politics of translation; poetics; standardization; and language shift, endangerment, and revitalization.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 693', 'THEORIZING CENTRAL EURASIA: THE PROBLEMS OF NATIONALISM', '29452', 'Class Status', 'F Friday 12:45 PM–3:15 PM', 'LH 120', 'Gardner Bovingdon', 14, NULL, 'Seminar', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'This course introduces students to nationalism''s key works and questions. How are nations and nationalism related? Are nations imagined and invented or ancient and enduring? Are nationalism, communism, and religiosity necessarily opposed? Are indigenous nationalisms more authentic than "official nationalisms"? Is Central Eurasian nationalism a "derivative discourse," imported from elsewhere?', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 890', 'PHD THESIS', '1259', 'Class Status', NULL, NULL, 'Oner Ozcelik', 5, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course serves two purposes: 1) it may be used for credit for advanced readings related to doctoral research; 2) it maintains one''s student status as Ph.D candidate ("ABD") while researching and writing the Ph.D dissertation. In either function, this class is repeatable.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 890', 'PHD THESIS', '4178', 'Class Status', NULL, NULL, 'Oner Ozcelik', 5, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course serves two purposes: 1) it may be used for credit for advanced readings related to doctoral research; 2) it maintains one''s student status as Ph.D candidate ("ABD") while researching and writing the Ph.D dissertation. In either function, this class is repeatable.', ARRAY[]::TEXT[], NULL),
    ('CEUS-R 890', 'PHD THESIS', '6849', 'Class Status', NULL, NULL, 'Oner Ozcelik', 4, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'This course serves two purposes: 1) it may be used for credit for advanced readings related to doctoral research; 2) it maintains one''s student status as Ph.D candidate ("ABD") while researching and writing the Ph.D dissertation. In either function, this class is repeatable.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 101', 'INTRODUCTORY FINNISH I', '1237', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 3:30 PM–4:20 PM', 'WB WEB', 'Piibi-Kai Kivik', 11, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An introduction to Finnish for students with no previous knowledge of Finnish language. Emphasizes skills for everyday situations in Finland. Aids understanding of simple spoken Finnish for familiar topics and the main points of brief messages. Students also study Finnish culture and history.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 103', 'INTRODUCTORY ESTONIAN I', '1236', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'GA 4024 WB WEB', 'Piibi-Kai Kivik', 4, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES, WEB-BASED CLASS', ARRAY[]::TEXT[], 'Assumes no previous knowledge of Estonian. Emphasizes oral communication with attention to reading, writing, speaking, and listening. With basic vocabulary and structures, students can talk about themselves and immediate surroundings, interact in service encounters, read short texts and write notes. Introduction to Estonian culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 103', 'INTRODUCTORY ESTONIAN I', '7918', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES, WEB-BASED CLASS', ARRAY[]::TEXT[], 'Assumes no previous knowledge of Estonian. Emphasizes oral communication with attention to reading, writing, speaking, and listening. With basic vocabulary and structures, students can talk about themselves and immediate surroundings, interact in service encounters, read short texts and write notes. Introduction to Estonian culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 103', 'INTRODUCTORY ESTONIAN I', '10876', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES, WEB-BASED CLASS', ARRAY[]::TEXT[], 'Assumes no previous knowledge of Estonian. Emphasizes oral communication with attention to reading, writing, speaking, and listening. With basic vocabulary and structures, students can talk about themselves and immediate surroundings, interact in service encounters, read short texts and write notes. Introduction to Estonian culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 111', 'INTRODUCTORY UZBEK I', '7947', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Malik Hodjaev', 4, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduction to Uzbekistan''s literary language, using Latin and Cyrillic alphabets. Conversation, reading practice, journal writing, newspapers illustrating modern Uzbekistan, Uzbek videos, TV programs, and audiotapes used.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 111', 'INTRODUCTORY UZBEK I', '8268', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Malik Hodjaev', 4, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduction to Uzbekistan''s literary language, using Latin and Cyrillic alphabets. Conversation, reading practice, journal writing, newspapers illustrating modern Uzbekistan, Uzbek videos, TV programs, and audiotapes used.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 111', 'INTRODUCTORY UZBEK I', '8767', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 3032', 'Malik Hodjaev', 5, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduction to Uzbekistan''s literary language, using Latin and Cyrillic alphabets. Conversation, reading practice, journal writing, newspapers illustrating modern Uzbekistan, Uzbek videos, TV programs, and audiotapes used.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 113', 'INTRODUCTORY KAZAKH I', '37240', 'Class Status', 'Non Standard Session', 'WB WEB', 'Staff', 5, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'No previous knowledge of Kazakh required. Introduction to basic communication skills in Kazakh. Upon finishing, students will be able to use Kazakh in basic communicative contexts. Readings, class discussions, listening activities adapted from Kazakh language media programs. Films and extracurricular activities develop awareness of Kazakh culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 141', 'INTRODUCTORY HUNGARIAN I', '1238', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'GA 4030', 'Valeria Varga', 7, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Enables students to converse about basic topics, meet basic communicative needs, and read and write short texts with simple sentence patterns and everyday topics. Students learn to use fundamental Hungarian structures with comfort and confidence while learning about Hungarian lifestyle, society, and culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 141', 'INTRODUCTORY HUNGARIAN I', '7924', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Valeria Varga', 4, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Enables students to converse about basic topics, meet basic communicative needs, and read and write short texts with simple sentence patterns and everyday topics. Students learn to use fundamental Hungarian structures with comfort and confidence while learning about Hungarian lifestyle, society, and culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 141', 'INTRODUCTORY HUNGARIAN I', '15224', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Valeria Varga', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Enables students to converse about basic topics, meet basic communicative needs, and read and write short texts with simple sentence patterns and everyday topics. Students learn to use fundamental Hungarian structures with comfort and confidence while learning about Hungarian lifestyle, society, and culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 151', 'INTRODUCTORY PERSIAN I', '5127', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SY 210 WB WEB', 'Narges Nematollahi', 10, NULL, 'Lecture', '4', 'SYCAMORE HALL, WEB-BASED CLASS', ARRAY[]::TEXT[], 'No previous knowledge of Persian required. Introduces basic communication skills in modern standard Persian and familiarizes students with Persian''s sounds, alphabet, and basic grammar. Students learn to read, write, speak, and comprehend simple to moderately complex sentences. Readings, class conversations, media programs, film 20 viewing, and cultural activities introduce Persian cultures.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 161', 'INTRODUCTORY MONGOLIAN I', '1239', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 4021', 'Tserenchunt Legden', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to Modern Mongolian in the Cyrillic script and to basic Mongolian pronunciation and grammar, along with knowledge of Mongolian culture and traditions. Students learn to conduct everyday conversations and use Mongolian''s main cases and verb tenses in conversation and writing.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 161', 'INTRODUCTORY MONGOLIAN I', '7929', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Tserenchunt Legden', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to Modern Mongolian in the Cyrillic script and to basic Mongolian pronunciation and grammar, along with knowledge of Mongolian culture and traditions. Students learn to conduct everyday conversations and use Mongolian''s main cases and verb tenses in conversation and writing.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 161', 'INTRODUCTORY MONGOLIAN I', '8207', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Tserenchunt Legden', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introduction to Modern Mongolian in the Cyrillic script and to basic Mongolian pronunciation and grammar, along with knowledge of Mongolian culture and traditions. Students learn to conduct everyday conversations and use Mongolian''s main cases and verb tenses in conversation and writing.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 171', 'INTRODUCTORY TIBETAN I', '7935', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Gedun Rabsal', 4, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduces Tibetan language basics to students with no previous background in Tibetan. Students begin speaking, listening, reading, and writing basic grammar, building vocabulary, and developing idiomatic usage needed in everyday communication. Introduction to Tibetan culture and daily life.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 171', 'INTRODUCTORY TIBETAN I', '9544', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Gedun Rabsal', 10, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduces Tibetan language basics to students with no previous background in Tibetan. Students begin speaking, listening, reading, and writing basic grammar, building vocabulary, and developing idiomatic usage needed in everyday communication. Introduction to Tibetan culture and daily life.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 171', 'INTRODUCTORY TIBETAN I', '12368', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 4024', 'Gedun Rabsal', 8, NULL, 'Lecture', '4', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduces Tibetan language basics to students with no previous background in Tibetan. Students begin speaking, listening, reading, and writing basic grammar, building vocabulary, and developing idiomatic usage needed in everyday communication. Introduction to Tibetan culture and daily life.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 181', 'INTRODUCTORY TURKISH I', '1240', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'BH 221', 'Sibel Crum', 11, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduces English-speaking students to Turkish. Builds basic proficiency in modern Turkish for effective communication at beginning level in everyday situations. Listening, speaking, reading, and writing are covered in classroom activities and at-home practice. Establishes a solid linguistic and cultural foundation for future studies of Turkish.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 201', 'INTERMEDIATE FINNISH I', '37308', 'Class Status', 'WTh Wednesday, Thursday 6:40 PM–8:20 PM', 'BH 233 BH 233', 'Jeanne McGill', 3, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Geared to students who know the basics of Finnish to communicate in situations related to study, work, and leisure, while learning specific issues of Finnish culture and history. Methods are learner centered, communicative and often problem-based.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 203', 'INTERMEDIATE ESTONIAN I', '6983', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4024', 'Piibi-Kai Kivik', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Builds on skills acquired in introductory courses. First year topics are reviewed in more detail and new topics, such as seasons, holidays, traditions, and customs are added. Longer reading texts are introduced. Video materials train listening comprehension. Development of 12 conversation skills beyond the structured exchanges of the introductory level.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 203', 'INTERMEDIATE ESTONIAN I', '7641', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Builds on skills acquired in introductory courses. First year topics are reviewed in more detail and new topics, such as seasons, holidays, traditions, and customs are added. Longer reading texts are introduced. Video materials train listening comprehension. Development of 12 conversation skills beyond the structured exchanges of the introductory level.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 203', 'INTERMEDIATE ESTONIAN I', '10858', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 9, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Builds on skills acquired in introductory courses. First year topics are reviewed in more detail and new topics, such as seasons, holidays, traditions, and customs are added. Longer reading texts are introduced. Video materials train listening comprehension. Development of 12 conversation skills beyond the structured exchanges of the introductory level.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 211', 'INTERMEDIATE UZBEK I', '1246', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 3032', 'Malik Hodjaev', 1, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Increases fluency in speaking and develops listening and reading skills. With extensive conversation and reading practice, students extend their vocabulary and grammar fundamentals in the literary language of Uzbekistan. Journals, newspapers and authentic materials supplied via Internet, email, and Oncourse illustrate modern life and language in Uzbekistan.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 211', 'INTERMEDIATE UZBEK I', '7948', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Malik Hodjaev', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Increases fluency in speaking and develops listening and reading skills. With extensive conversation and reading practice, students extend their vocabulary and grammar fundamentals in the literary language of Uzbekistan. Journals, newspapers and authentic materials supplied via Internet, email, and Oncourse illustrate modern life and language in Uzbekistan.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 231', 'INTERMEDIATE UYGHUR I', '3376', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GY 4069', 'Gulnisa Nazarova', 4, NULL, 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Expands grammatical, lexical, and functional skills. Listening activities involve narratives, interviews from RFA (Uyghur Erkin Asiya Radiosi), and Uyghur TV. Contemporary Eastern Turkestan''s society is introduced to facilitate effective situational communication.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 231', 'INTERMEDIATE UYGHUR I', '7942', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Expands grammatical, lexical, and functional skills. Listening activities involve narratives, interviews from RFA (Uyghur Erkin Asiya Radiosi), and Uyghur TV. Contemporary Eastern Turkestan''s society is introduced to facilitate effective situational communication.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 231', 'INTERMEDIATE UYGHUR I', '10863', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Expands grammatical, lexical, and functional skills. Listening activities involve narratives, interviews from RFA (Uyghur Erkin Asiya Radiosi), and Uyghur TV. Contemporary Eastern Turkestan''s society is introduced to facilitate effective situational communication.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 241', 'INTERMEDIATE HUNGARIAN I', '1242', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4030', 'Valeria Varga', 1, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Helps students converse more fluently about personal and simple academic topics, articulate feelings and opinions, read short literary and scholarly texts, and write for basic personal, business, and academic purposes. Authentic texts and video teach about the lifestyle and socio-historical facts of Hungary.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 241', 'INTERMEDIATE HUNGARIAN I', '7925', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Helps students converse more fluently about personal and simple academic topics, articulate feelings and opinions, read short literary and scholarly texts, and write for basic personal, business, and academic purposes. Authentic texts and video teach about the lifestyle and socio-historical facts of Hungary.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 241', 'INTERMEDIATE HUNGARIAN I', '10841', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Helps students converse more fluently about personal and simple academic topics, articulate feelings and opinions, read short literary and scholarly texts, and write for basic personal, business, and academic purposes. Authentic texts and video teach about the lifestyle and socio-historical facts of Hungary.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 251', 'INTERMEDIATE PERSIAN I', '1247', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 318 BH 015', 'Narges Nematollahi', 9, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Covers a wide range of topics and intermediate to advanced grammar.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 255', 'INTERMEDIATE SORANI KURDISH I', '10385', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'HD TBA', 'Hewa Khalid', 9, NULL, 'Lecture', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'A continuation of CEUS-T 157, Intermediate Sorani Kurdish moves from basic communication to more detail-oriented conversations and introduces students to using native sources, such as newspapers, and other audio-visual media.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 255', 'INTERMEDIATE SORANI KURDISH I', '15209', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Hewa Khalid', 10, NULL, 'Lecture', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'A continuation of CEUS-T 157, Intermediate Sorani Kurdish moves from basic communication to more detail-oriented conversations and introduces students to using native sources, such as newspapers, and other audio-visual media.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 261', 'INTERMEDIATE MONGOLIAN I', '1243', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4021', 'Tserenchunt Legden', 1, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Expands the basic Mongolian conversation, grammar, reading, and writing skills mastered in first year. Introduces the most useful kinds of compound and complex sentences and develops skills to use them in conversation and writing. Furthers knowledge of Mongolian culture and tradition.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 261', 'INTERMEDIATE MONGOLIAN I', '7930', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Expands the basic Mongolian conversation, grammar, reading, and writing skills mastered in first year. Introduces the most useful kinds of compound and complex sentences and develops skills to use them in conversation and writing. Furthers knowledge of Mongolian culture and tradition.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 261', 'INTERMEDIATE MONGOLIAN I', '10878', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Expands the basic Mongolian conversation, grammar, reading, and writing skills mastered in first year. Introduces the most useful kinds of compound and complex sentences and develops skills to use them in conversation and writing. Furthers knowledge of Mongolian culture and tradition.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 271', 'INTERMEDIATE TIBETAN I', '1244', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WH 114', 'Gedun Rabsal', 5, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Further develops skills in Tibetan for effective communication. Speaking, listening, reading, and writing skills are developed throughout the course with attention to grammar. Special attention to classical Tibetan readings.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 271', 'INTERMEDIATE TIBETAN I', '7936', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Gedun Rabsal', 5, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Further develops skills in Tibetan for effective communication. Speaking, listening, reading, and writing skills are developed throughout the course with attention to grammar. Special attention to classical Tibetan readings.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 271', 'INTERMEDIATE TIBETAN I', '9546', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Gedun Rabsal', 5, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Further develops skills in Tibetan for effective communication. Speaking, listening, reading, and writing skills are developed throughout the course with attention to grammar. Special attention to classical Tibetan readings.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 281', 'INTERMEDIATE TURKISH I', '1245', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'GA 0003', 'Sibel Crum', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Expands communicative skills, grammar, and vocabulary skills. Class activities and homework involve listening, speaking, reading, and writing. Special attention paid to building richer vocabulary, developing competence in the vernacular, and improving reading. Recordings, films, handicrafts, and cartoons used in context.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CEUS-T 298', 'INTERMEDIATE CENTRAL EURASIAN LANGUAGES I', '13097', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'FQ B002', 'Piibi-Kai Kivik, Adina Daniiar kyzy', 2, NULL, 'Lecture', '4', 'MARTIN HALL', ARRAY[]::TEXT[], 'Various languages of Central Eurasia will be offered when available and will be listed in the online Schedule of Classes.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 301', 'ADVANCED FINNISH I', '37307', 'Class Status', 'WTh Wednesday, Thursday 6:40 PM–8:20 PM', 'BH 233 BH 233', 'Jeanne McGill', 3, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Teaches advanced skills desirable for academic life and work. The goal is to communicate effectively in demanding oral and written situations, and to handle both writing and speech on demanding topics. Also widens knowledge of Finnish culture and history.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 303', 'ADVANCED ESTONIAN I', '6502', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4024', 'Piibi-Kai Kivik', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Builds students'' confidence as language users via class discussion of newspaper articles, fiction and poetry, class presentations, journal entries, summaries of articles, film and news clips, short essays, TV broadcasts, and audiotape recordings. Focuses on structures of formal written Estonian and different registers of oral production.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 303', 'ADVANCED ESTONIAN I', '7919', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Builds students'' confidence as language users via class discussion of newspaper articles, fiction and poetry, class presentations, journal entries, summaries of articles, film and news clips, short essays, TV broadcasts, and audiotape recordings. Focuses on structures of formal written Estonian and different registers of oral production.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 303', 'ADVANCED ESTONIAN I', '11827', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 9, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Builds students'' confidence as language users via class discussion of newspaper articles, fiction and poetry, class presentations, journal entries, summaries of articles, film and news clips, short essays, TV broadcasts, and audiotape recordings. Focuses on structures of formal written Estonian and different registers of oral production.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 311', 'ADVANCED UZBEK I', '5251', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 3032', 'Malik Hodjaev', 1, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Increases oral fluency, and develops listening, reading and writing based on literary Uzbek. Enables students to do research in history, culture, and politics. Extensive conversation and reading practice uses journals and newspapers illustrating modern Uzbekistan, Web sites, videos, TV, and audiotapes.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 311', 'ADVANCED UZBEK I', '7949', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Malik Hodjaev', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Increases oral fluency, and develops listening, reading and writing based on literary Uzbek. Enables students to do research in history, culture, and politics. Extensive conversation and reading practice uses journals and newspapers illustrating modern Uzbekistan, Web sites, videos, TV, and audiotapes.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 331', 'ADVANCED UYGHUR I', '6503', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GY 4069', 'Gulnisa Nazarova', 4, NULL, 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Students give oral, reading, and writing presentations; participate in class discussions; and practice translation. Excerpts from novels, movies, newspapers, and other media develop knowledge of Uyghur culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 331', 'ADVANCED UYGHUR I', '7943', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Students give oral, reading, and writing presentations; participate in class discussions; and practice translation. Excerpts from novels, movies, newspapers, and other media develop knowledge of Uyghur culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 331', 'ADVANCED UYGHUR I', '11707', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Students give oral, reading, and writing presentations; participate in class discussions; and practice translation. Excerpts from novels, movies, newspapers, and other media develop knowledge of Uyghur culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 341', 'ADVANCED HUNGARIAN I', '4507', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4030', 'Valeria Varga', 1, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Assumes four semesters of Hungarian and substantial knowledge of grammar, syntax, and vocabulary. Enables students to converse about moderately complex personal, social, and academic topics; to read and understand a full range of literary genres; and to write and translate to meet most personal and academic needs.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 341', 'ADVANCED HUNGARIAN I', '7642', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Assumes four semesters of Hungarian and substantial knowledge of grammar, syntax, and vocabulary. Enables students to converse about moderately complex personal, social, and academic topics; to read and understand a full range of literary genres; and to write and translate to meet most personal and academic needs.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 341', 'ADVANCED HUNGARIAN I', '11705', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Assumes four semesters of Hungarian and substantial knowledge of grammar, syntax, and vocabulary. Enables students to converse about moderately complex personal, social, and academic topics; to read and understand a full range of literary genres; and to write and translate to meet most personal and academic needs.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 351', 'ADVANCED PERSIAN I', '4503', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 318 BH 015', 'Narges Nematollahi', 9, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Students examine the classical Persian tradition''s rich legacy of historical, literary, and religious writings and learn the grammatical and lexical differences distinguishing classical 4 from modern Persian. Introduction to basic research tools and reference works. Readings cover the range of classical Persian texts.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 351', 'ADVANCED PERSIAN I', '15255', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Narges Nematollahi', 5, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Students examine the classical Persian tradition''s rich legacy of historical, literary, and religious writings and learn the grammatical and lexical differences distinguishing classical 4 from modern Persian. Introduction to basic research tools and reference works. Readings cover the range of classical Persian texts.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 351', 'ADVANCED PERSIAN I', '15256', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Narges Nematollahi', 5, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Students examine the classical Persian tradition''s rich legacy of historical, literary, and religious writings and learn the grammatical and lexical differences distinguishing classical 4 from modern Persian. Introduction to basic research tools and reference works. Readings cover the range of classical Persian texts.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 355', 'ADVANCED SORANI KURDISH I', '10440', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'HD TBA', 'Hewa Khalid', 9, NULL, 'Lecture', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Provides skills and practice in listening, speaking, reading, and writing necessary to live and operate in the target-language environment. Focuses on the use of native sources to build competence and preparation for study abroad experiences.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 355', 'ADVANCED SORANI KURDISH I', '15211', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Hewa Khalid', 10, NULL, 'Lecture', '4', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Provides skills and practice in listening, speaking, reading, and writing necessary to live and operate in the target-language environment. Focuses on the use of native sources to build competence and preparation for study abroad experiences.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 361', 'ADVANCED MONGOLIAN I', '4508', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4021', 'Tserenchunt Legden', 1, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Review of compound and complex sentences. Develops a sense of Mongolian literary style through the reading of diverse materials. In-class oral presentations, discussions, and role-play increase fluency. Translation exercises enhance knowledge of Mongolian culture and history.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 361', 'ADVANCED MONGOLIAN I', '7931', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Review of compound and complex sentences. Develops a sense of Mongolian literary style through the reading of diverse materials. In-class oral presentations, discussions, and role-play increase fluency. Translation exercises enhance knowledge of Mongolian culture and history.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 361', 'ADVANCED MONGOLIAN I', '15213', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Review of compound and complex sentences. Develops a sense of Mongolian literary style through the reading of diverse materials. In-class oral presentations, discussions, and role-play increase fluency. Translation exercises enhance knowledge of Mongolian culture and history.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 371', 'ADVANCED TIBETAN I', '6504', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WH 114', 'Gedun Rabsal', 5, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Expands knowledge of grammar with reading and composition exercises, and translation of general texts from Tibetan into English. Focuses on reading in modern and classical Tibetan.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 371', 'ADVANCED TIBETAN I', '7937', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Gedun Rabsal', 5, NULL, 'Lecture', '4', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Expands knowledge of grammar with reading and composition exercises, and translation of general texts from Tibetan into English. Focuses on reading in modern and classical Tibetan.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 381', 'ADVANCED TURKISH I', '4505', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'GA 0003', 'Sibel Crum', 5, NULL, 'Lecture', '4', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Requires written reports after watching Turkish TV news. Class activities improve language skills of listening, speaking, reading, and writing. Opportunity to interact with native speakers outside of class.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 398', 'ADVANCED CENTRAL EURASIAN LANGUAGES I', '10112', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'FQ B002', 'Piibi-Kai Kivik, Adina Daniiar kyzy', 2, NULL, 'Lecture', '3', 'MARTIN HALL', ARRAY[]::TEXT[], 'Various languages of Central Eurasia will be offered when available and will be listed in the online Schedule of Classes.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 487', 'CLASSICAL TURKISH: OTTOMAN', '12090', 'Class Status', 'TuTh Tuesday, Thursday 4:20 PM–6:50 PM', 'BH 135', 'Kemal Silay', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Arabic script as adopted for Ottoman documents. Basic Arabic and Persian grammar will also be incorporated. After reaching a comfortable level with the orthography, early twentieth-century Ottoman texts will be read. Also includes the deciphering authentic Ottoman manuscripts.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '8205', 'Class Status', NULL, NULL, 'Piibi-Kai Kivik', 2, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '9004', 'Class Status', NULL, NULL, 'Gedun Rabsal', 2, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '10512', 'Class Status', NULL, NULL, 'Piibi-Kai Kivik', 2, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
