    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '11173', 'Class Status', NULL, NULL, 'Gulnisa Nazarova', 3, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '12844', 'Class Status', NULL, NULL, 'Malik Hodjaev', 3, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '33606', 'Class Status', 'M Monday 3:55 PM–6:25 PM', 'PV 270', 'Ron Sela', 7, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '10725', 'Class Status', NULL, NULL, 'Tserenchunt Legden', 5, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '11372', 'Class Status', NULL, NULL, 'Valeria Varga', 4, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '15052', 'Class Status', NULL, NULL, 'Piibi-Kai Kivik', 2, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '35002', 'Class Status', 'TuTh Tuesday, Thursday 9:00 AM–10:15 AM', 'WB WEB', 'Narges Nematollahi', 3, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '35003', 'Class Status', 'TuTh Tuesday, Thursday 9:00 AM–10:15 AM', 'WB WEB', 'Narges Nematollahi', 2, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 493', 'ADVANCED STUDY OF A CENTRAL EURASIAN LANGUAGE I', '35004', 'Class Status', 'TuTh Tuesday, Thursday 9:00 AM–10:15 AM', 'WB WEB', 'Narges Nematollahi', 1, NULL, 'Seminar', '4', 'SPEA', ARRAY[]::TEXT[], 'Advanced study of a Central Eurasian language beyond the 300 level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 501', 'INTRODUCTORY FINNISH I', '1249', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 3:30 PM–4:20 PM', 'WB WEB', 'Piibi-Kai Kivik', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course introduces Finnish to students with no previous knowledge. We emphasize skills for everyday situations in Finland. You will also understand simple spoken Finnish for familiar topics and grasp the main points of brief messages. You will also learn the basic facts of Finnish culture and history.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 503', 'INTRODUCTORY ESTONIAN I', '1250', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'GA 4024 WB WEB', 'Piibi-Kai Kivik', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES, WEB-BASED CLASS', ARRAY[]::TEXT[], 'Assuming no previous knowledge of Estonian, Introductory Estonian I emphasizes oral communications, with attention to reading, writing, speaking and listening. With basic vocabulary and structures, students can talk about themselves and immediate surroundings, interact in service encounters, read short texts and write notes. Students also learn about Estonian culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 503', 'INTRODUCTORY ESTONIAN I', '7920', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES, WEB-BASED CLASS', ARRAY[]::TEXT[], 'Assuming no previous knowledge of Estonian, Introductory Estonian I emphasizes oral communications, with attention to reading, writing, speaking and listening. With basic vocabulary and structures, students can talk about themselves and immediate surroundings, interact in service encounters, read short texts and write notes. Students also learn about Estonian culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 503', 'INTRODUCTORY ESTONIAN I', '10877', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES, WEB-BASED CLASS', ARRAY[]::TEXT[], 'Assuming no previous knowledge of Estonian, Introductory Estonian I emphasizes oral communications, with attention to reading, writing, speaking and listening. With basic vocabulary and structures, students can talk about themselves and immediate surroundings, interact in service encounters, read short texts and write notes. Students also learn about Estonian culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 511', 'INTRODUCTORY UZBEK I', '7950', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Malik Hodjaev', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory Uzbek I introduces Uzbekistan''s literary language, using Latin and Cyrillic alphabets. Conversation, reading practice, journal writing, newspapers illustrating modern Uzbekistan, Uzbek videos, TV programs, and audio tapes will be used. Students will use Oncourse and email to print out teaching materials and to turn in their assignments.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 511', 'INTRODUCTORY UZBEK I', '8269', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Malik Hodjaev', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory Uzbek I introduces Uzbekistan''s literary language, using Latin and Cyrillic alphabets. Conversation, reading practice, journal writing, newspapers illustrating modern Uzbekistan, Uzbek videos, TV programs, and audio tapes will be used. Students will use Oncourse and email to print out teaching materials and to turn in their assignments.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 511', 'INTRODUCTORY UZBEK I', '8768', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 3032', 'Malik Hodjaev', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory Uzbek I introduces Uzbekistan''s literary language, using Latin and Cyrillic alphabets. Conversation, reading practice, journal writing, newspapers illustrating modern Uzbekistan, Uzbek videos, TV programs, and audio tapes will be used. Students will use Oncourse and email to print out teaching materials and to turn in their assignments.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 513', 'INTRODUCTORY KAZAKH I', '37241', 'Class Status', 'Non Standard Session', 'WB WEB', 'Staff', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This class introduces basic communication skills in Kazakh. Students learn the sounds, alphabet, and basic grammar. Upon finishing, students will be able to use Kazakh in basic communicative contexts. Readings, class discussions, listening activities adapted from Kazakh language media programs. Films and extra-curricular cultural activities develop awareness of Kazakh culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 541', 'INTRODUCTORY HUNGARIAN I', '1248', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'GA 4030', 'Valeria Varga', 7, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introductory Hungarian enables students to converse about basic topics, meet basic communicative needs, and read and write short texts with simple sentence patterns and everyday topics. Students learn to use fundamental Hungarian structures with comfort and confidence. Students also learn about Hungarian lifestyle, society and culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 541', 'INTRODUCTORY HUNGARIAN I', '7926', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Valeria Varga', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introductory Hungarian enables students to converse about basic topics, meet basic communicative needs, and read and write short texts with simple sentence patterns and everyday topics. Students learn to use fundamental Hungarian structures with comfort and confidence. Students also learn about Hungarian lifestyle, society and culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 541', 'INTRODUCTORY HUNGARIAN I', '15225', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Valeria Varga', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introductory Hungarian enables students to converse about basic topics, meet basic communicative needs, and read and write short texts with simple sentence patterns and everyday topics. Students learn to use fundamental Hungarian structures with comfort and confidence. Students also learn about Hungarian lifestyle, society and culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 551', 'INTRODUCTORY PERSIAN I', '4501', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'SY 210 WB WEB', 'Narges Nematollahi', 10, NULL, 'Lecture', '3', 'SYCAMORE HALL, WEB-BASED CLASS', ARRAY[]::TEXT[], 'This class introduces basic communication skills in Modern Standard Persian and familiarizes students with Persian''s sounds, alphabet, and basic grammar. Students will learn to read, write, speak, and comprehend simple to moderately complex sentences. Readings, class conversations, media programs, film viewing, and cultural activities will also introduce Persian culture.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 561', 'INTRODUCTORY MONGOLIAN I', '1251', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 4021', 'Tserenchunt Legden', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introductory Mongolian I introduces students to modern Mongolian in the Cyrillic script, introducing basic Mongolian pronunciation and grammar, along with knowledge of Mongolian culture and traditions. By the end of the semester, students can conduct everyday conversations and use Mongolian''s main cases and verb tenses in conversation and writing.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 561', 'INTRODUCTORY MONGOLIAN I', '7932', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Tserenchunt Legden', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introductory Mongolian I introduces students to modern Mongolian in the Cyrillic script, introducing basic Mongolian pronunciation and grammar, along with knowledge of Mongolian culture and traditions. By the end of the semester, students can conduct everyday conversations and use Mongolian''s main cases and verb tenses in conversation and writing.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 561', 'INTRODUCTORY MONGOLIAN I', '8208', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Tserenchunt Legden', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Introductory Mongolian I introduces students to modern Mongolian in the Cyrillic script, introducing basic Mongolian pronunciation and grammar, along with knowledge of Mongolian culture and traditions. By the end of the semester, students can conduct everyday conversations and use Mongolian''s main cases and verb tenses in conversation and writing.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 571', 'INTRODUCTORY TIBETAN I', '7938', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Gedun Rabsal', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory Tibetan I introduces Tibetan language basics to students with no previous background. We will begin speaking, listening, reading and writing. We cover the basic grammar, build vocabulary, and develop idiomatic usage needed in everyday communication. The course will also introduce learners to Tibetan culture and daily life.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 571', 'INTRODUCTORY TIBETAN I', '9545', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'GA 4024', 'Gedun Rabsal', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory Tibetan I introduces Tibetan language basics to students with no previous background. We will begin speaking, listening, reading and writing. We cover the basic grammar, build vocabulary, and develop idiomatic usage needed in everyday communication. The course will also introduce learners to Tibetan culture and daily life.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 571', 'INTRODUCTORY TIBETAN I', '10997', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'WB WEB', 'Gedun Rabsal', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory Tibetan I introduces Tibetan language basics to students with no previous background. We will begin speaking, listening, reading and writing. We cover the basic grammar, build vocabulary, and develop idiomatic usage needed in everyday communication. The course will also introduce learners to Tibetan culture and daily life.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 581', 'INTRODUCTORY TURKISH I', '4524', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'BH 221', 'Sibel Crum', 11, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introductory Turkish I introduces English-speaking students to Turkish. Students build basic proficiency in modern Turkish and communicate at beginner''s level in everyday situations. Listening, speaking, reading, and writing are covered in classroom activities and at-home practice and a sound linguistic and cultural foundation is laid for future studies of Turkish.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 601', 'INTERMEDIATE FINNISH I', '4550', 'Class Status', 'WTh Wednesday, Thursday 6:40 PM–8:20 PM', 'BH 233 BH 233', 'Jeanne McGill', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Intermediate Finnish I helps students who know the basics of Finnish to communicate in situations related to study, work and leisure, while learning specific issues of Finnish culture and history. Methods are learner centered, communicative and often problem-based, involving both instructor and peer learners.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 603', 'INTERMEDIATE ESTONIAN I', '6984', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4024', 'Piibi-Kai Kivik', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course builds on skills acquired during Introductory Estonian. First-year topics are reviewed in more detail and new topics, such as seasons, holidays, traditions and customs added. Longer reading texts are introduced. Video materials train listening comprehension. Conversation skills are developed beyond the structured exchanges learned at the Intro level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 603', 'INTERMEDIATE ESTONIAN I', '7921', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course builds on skills acquired during Introductory Estonian. First-year topics are reviewed in more detail and new topics, such as seasons, holidays, traditions and customs added. Longer reading texts are introduced. Video materials train listening comprehension. Conversation skills are developed beyond the structured exchanges learned at the Intro level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 603', 'INTERMEDIATE ESTONIAN I', '10859', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 9, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course builds on skills acquired during Introductory Estonian. First-year topics are reviewed in more detail and new topics, such as seasons, holidays, traditions and customs added. Longer reading texts are introduced. Video materials train listening comprehension. Conversation skills are developed beyond the structured exchanges learned at the Intro level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 611', 'INTERMEDIATE UZBEK I', '1254', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 3032', 'Malik Hodjaev', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intermediate Uzbek increases students'' fluency in speaking and develops listening and reading skills. With extensive conversation and reading practice, students extend their vocabulary and grammar fundamentals in the literary language of Uzbekistan. Journals, newspapers and authentic materials supplied via Internet, e-mail and Oncourse illustrate modern life and language in Uzbekistan.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 611', 'INTERMEDIATE UZBEK I', '7951', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Malik Hodjaev', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intermediate Uzbek increases students'' fluency in speaking and develops listening and reading skills. With extensive conversation and reading practice, students extend their vocabulary and grammar fundamentals in the literary language of Uzbekistan. Journals, newspapers and authentic materials supplied via Internet, e-mail and Oncourse illustrate modern life and language in Uzbekistan.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 611', 'INTERMEDIATE UZBEK I', '11850', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Malik Hodjaev', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intermediate Uzbek increases students'' fluency in speaking and develops listening and reading skills. With extensive conversation and reading practice, students extend their vocabulary and grammar fundamentals in the literary language of Uzbekistan. Journals, newspapers and authentic materials supplied via Internet, e-mail and Oncourse illustrate modern life and language in Uzbekistan.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 623', 'CHAGHATAY', '33607', 'Class Status', 'M Monday 3:55 PM–6:25 PM', 'PV 270', 'Ron Sela', 7, NULL, 'Lecture', '3', 'SPEA', ARRAY[]::TEXT[], 'This course gives a basic knowledge of Chaghatay, the classical version of Uzbek and the common literary language of all Central Asian Turks from the 15th to the early 20th century. The course surveys Chaghatay literature, grammar, and the writing system together with the reading of Chaghatay texts, chiefly historical.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 631', 'INTERMEDIATE UYGHUR I', '3377', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GY 4069', 'Gulnisa Nazarova', 4, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Intermediate Uyghur will expand the learner''s grammatical, lexical, and functional skills. Listening activities involve narratives, interviews from RFA (Uyghur Erkin Asiya Radiosi), Uyghur TV, etc. Partner work and discussions are also used. Contemporary Eastern Turkestan''s society will be introduced, so students can communicate properly in different situations, purposes, and roles.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 631', 'INTERMEDIATE UYGHUR I', '7945', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Intermediate Uyghur will expand the learner''s grammatical, lexical, and functional skills. Listening activities involve narratives, interviews from RFA (Uyghur Erkin Asiya Radiosi), Uyghur TV, etc. Partner work and discussions are also used. Contemporary Eastern Turkestan''s society will be introduced, so students can communicate properly in different situations, purposes, and roles.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 631', 'INTERMEDIATE UYGHUR I', '10864', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Intermediate Uyghur will expand the learner''s grammatical, lexical, and functional skills. Listening activities involve narratives, interviews from RFA (Uyghur Erkin Asiya Radiosi), Uyghur TV, etc. Partner work and discussions are also used. Contemporary Eastern Turkestan''s society will be introduced, so students can communicate properly in different situations, purposes, and roles.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 641', 'INTERMEDIATE HUNGARIAN I', '1252', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4030', 'Valeria Varga', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intermediate Hungarian helps students converse more fluently about personal and simple academic topics, articulate their feelings and opinions, read short literary and scholarly texts, and write for basic personal, business, and academic purposes. Authentic texts and video teach about the life-style and social-historical facts of Hungary.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 641', 'INTERMEDIATE HUNGARIAN I', '7927', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intermediate Hungarian helps students converse more fluently about personal and simple academic topics, articulate their feelings and opinions, read short literary and scholarly texts, and write for basic personal, business, and academic purposes. Authentic texts and video teach about the life-style and social-historical facts of Hungary.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 641', 'INTERMEDIATE HUNGARIAN I', '10810', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intermediate Hungarian helps students converse more fluently about personal and simple academic topics, articulate their feelings and opinions, read short literary and scholarly texts, and write for basic personal, business, and academic purposes. Authentic texts and video teach about the life-style and social-historical facts of Hungary.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 651', 'INTERMEDIATE PERSIAN I', '4502', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 318 BH 015', 'Narges Nematollahi', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Welcome to Intermediate Persian! After starting with a grammar review, we will cover a wide range of topics, and intermediate to advanced grammar.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 655', 'INTERMEDIATE SORANI KURDISH I', '11171', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'HD TBA', 'Hewa Khalid', 9, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Intermediate Sorani Kurdish will help students will continue where students left off, bringing them from basic communication to more detail-oriented conversations. We will also start using native sources such as newspapers and other audio-visual media.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 655', 'INTERMEDIATE SORANI KURDISH I', '15210', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Hewa Khalid', 10, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Intermediate Sorani Kurdish will help students will continue where students left off, bringing them from basic communication to more detail-oriented conversations. We will also start using native sources such as newspapers and other audio-visual media.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 661', 'INTERMEDIATE MONGOLIAN I', '1255', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4021', 'Tserenchunt Legden', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course expands the basic Mongolian conversation, grammar, reading and writing skills mastered in first year. The most useful kinds of compound and complex sentences of Mongolian are introduced and skills developed to use them in conversation and writing. Students also learn more about Mongolian culture and traditions.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 661', 'INTERMEDIATE MONGOLIAN I', '7933', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course expands the basic Mongolian conversation, grammar, reading and writing skills mastered in first year. The most useful kinds of compound and complex sentences of Mongolian are introduced and skills developed to use them in conversation and writing. Students also learn more about Mongolian culture and traditions.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 661', 'INTERMEDIATE MONGOLIAN I', '10879', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course expands the basic Mongolian conversation, grammar, reading and writing skills mastered in first year. The most useful kinds of compound and complex sentences of Mongolian are introduced and skills developed to use them in conversation and writing. Students also learn more about Mongolian culture and traditions.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 671', 'INTERMEDIATE TIBETAN I', '1256', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WH 114', 'Gedun Rabsal', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Intermediate Tibetan further develops the students'' ability to use Tibetan language for meaningful communication. Speaking, listening, reading and writing skills are developed throughout the course with due attention to grammar. Special attention is devoted to classical Tibetan readings.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 671', 'INTERMEDIATE TIBETAN I', '7939', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Gedun Rabsal', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Intermediate Tibetan further develops the students'' ability to use Tibetan language for meaningful communication. Speaking, listening, reading and writing skills are developed throughout the course with due attention to grammar. Special attention is devoted to classical Tibetan readings.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 671', 'INTERMEDIATE TIBETAN I', '9547', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Gedun Rabsal', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Intermediate Tibetan further develops the students'' ability to use Tibetan language for meaningful communication. Speaking, listening, reading and writing skills are developed throughout the course with due attention to grammar. Special attention is devoted to classical Tibetan readings.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 681', 'INTERMEDIATE TURKISH I', '1253', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'GA 0003', 'Sibel Crum', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Intermediate Turkish I expands the communicative skills, grammar and vocabulary skills mastered in Introductory Turkish. Class activities and homework involve listening, speaking, reading and writing. Special attention paid to building richer vocabulary, developing competence in the vernacular, and improving reading. Recordings, films, handicrafts, and cartoons used in context.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 685', 'CLASSICAL TURKISH: OTTOMAN', '12091', 'Class Status', 'TuTh Tuesday, Thursday 4:20 PM–6:50 PM', 'BH 135', 'Kemal Silay', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The first semester focuses on the Arabic script as used in Ottoman. Relevant Arabic and Persian grammar will be incorporated into the lectures and exercises. We will read and analyze (morphology and syntax) twentieth-century printed Ottoman texts. Course structure adjusted according to students'' level.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 698', 'INTERMEDIATE CENTRAL EURASIAN LANGUAGES I', '13098', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'FQ B002', 'Piibi-Kai Kivik, Adina Daniiar kyzy', 2, NULL, 'Lecture', '3', 'MARTIN HALL', ARRAY[]::TEXT[], 'This variable titles class is used for fall semester of intermediate-level modern language classes which do not yet have their own number. Such languages will be Uralic; Altaic; Iranian; or Tibeto-Burman languages of the Tibetan Plateau-Himalayas region. Students may not use more than one such language for departmental degree requirements.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 701', 'ADVANCED FINNISH I', '4520', 'Class Status', 'WTh Wednesday, Thursday 6:40 PM–8:20 PM', 'BH 233 BH 233', 'Jeanne McGill', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'This course teaches advanced skills desirable for academic life and work. The goal is to communicate effectively in demanding oral and written situations, and to handle both writing and speech on demanding topics. You will also widen your knowledge on Finnish culture and history.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 703', 'ADVANCED ESTONIAN I', '6427', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4024', 'Piibi-Kai Kivik', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course builds students'' confidence as language users via class discussion of newspaper articles, fiction and poetry, class presentations, journal entries, summaries of articles, films and news clips, short essays, TV broadcasts, and audio tape recordings. We focus on structures of formal written Estonian and different registers of oral production.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 703', 'ADVANCED ESTONIAN I', '7922', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course builds students'' confidence as language users via class discussion of newspaper articles, fiction and poetry, class presentations, journal entries, summaries of articles, films and news clips, short essays, TV broadcasts, and audio tape recordings. We focus on structures of formal written Estonian and different registers of oral production.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 703', 'ADVANCED ESTONIAN I', '11828', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Piibi-Kai Kivik', 9, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'This course builds students'' confidence as language users via class discussion of newspaper articles, fiction and poetry, class presentations, journal entries, summaries of articles, films and news clips, short essays, TV broadcasts, and audio tape recordings. We focus on structures of formal written Estonian and different registers of oral production.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 711', 'ADVANCED UZBEK I', '7952', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Malik Hodjaev', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced Uzbek I increases oral fluency, and develops listening, reading and writing, based on literary Uzbek, to enable students to do research in history, culture, politics, etc. We do extensive conversation and reading practice, using journals and newspapers illustrating modern Uzbekistan, Internet websites, Oncourse, videos, TV programs and audio tapes.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 711', 'ADVANCED UZBEK I', '12657', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 3032', 'Malik Hodjaev', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced Uzbek I increases oral fluency, and develops listening, reading and writing, based on literary Uzbek, to enable students to do research in history, culture, politics, etc. We do extensive conversation and reading practice, using journals and newspapers illustrating modern Uzbekistan, Internet websites, Oncourse, videos, TV programs and audio tapes.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 711', 'ADVANCED UZBEK I', '13101', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Malik Hodjaev', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced Uzbek I increases oral fluency, and develops listening, reading and writing, based on literary Uzbek, to enable students to do research in history, culture, politics, etc. We do extensive conversation and reading practice, using journals and newspapers illustrating modern Uzbekistan, Internet websites, Oncourse, videos, TV programs and audio tapes.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 731', 'ADVANCED UYGHUR I', '6429', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GY 4069', 'Gulnisa Nazarova', 4, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'In Advanced Uyghur I students will give oral, reading, and writing presentations, participate in class discussions, and practice translation. Excerpts from novels, movies, newspapers, etc., will develop knowledge of Uyghur culture. Students will need a strong drive to contribute to the whole class as well as individual meetings.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 731', 'ADVANCED UYGHUR I', '7946', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'In Advanced Uyghur I students will give oral, reading, and writing presentations, participate in class discussions, and practice translation. Excerpts from novels, movies, newspapers, etc., will develop knowledge of Uyghur culture. Students will need a strong drive to contribute to the whole class as well as individual meetings.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 731', 'ADVANCED UYGHUR I', '11708', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Gulnisa Nazarova', 6, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'In Advanced Uyghur I students will give oral, reading, and writing presentations, participate in class discussions, and practice translation. Excerpts from novels, movies, newspapers, etc., will develop knowledge of Uyghur culture. Students will need a strong drive to contribute to the whole class as well as individual meetings.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 741', 'ADVANCED HUNGARIAN I', '4517', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4030', 'Valeria Varga', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Assuming four semesters of Hungarian and substantial knowledge of grammar, syntax, and vocabulary, this course will enable students to converse about moderately complex personal, social, and academic topics, to read and understand a full range of literary genres, and to write and translate to meet most personal and academic needs.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 741', 'ADVANCED HUNGARIAN I', '7928', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Assuming four semesters of Hungarian and substantial knowledge of grammar, syntax, and vocabulary, this course will enable students to converse about moderately complex personal, social, and academic topics, to read and understand a full range of literary genres, and to write and translate to meet most personal and academic needs.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 741', 'ADVANCED HUNGARIAN I', '11706', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB WB WEB', 'Valeria Varga', 2, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Assuming four semesters of Hungarian and substantial knowledge of grammar, syntax, and vocabulary, this course will enable students to converse about moderately complex personal, social, and academic topics, to read and understand a full range of literary genres, and to write and translate to meet most personal and academic needs.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 751', 'ADVANCED PERSIAN I', '4504', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'BH 318 BH 015', 'Narges Nematollahi', 9, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In this course, students will examine the classical Persian tradition''s rich legacy of historical, literary, and religious writings. Students will learn the grammatical and lexical differences distinguishing classical from modern Persian, and will be introduced to basic research tools and reference works. Readings cover the range of classical Persian texts.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 751', 'ADVANCED PERSIAN I', '15258', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Narges Nematollahi', 5, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In this course, students will examine the classical Persian tradition''s rich legacy of historical, literary, and religious writings. Students will learn the grammatical and lexical differences distinguishing classical from modern Persian, and will be introduced to basic research tools and reference works. Readings cover the range of classical Persian texts.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 751', 'ADVANCED PERSIAN I', '15259', 'Class Status', 'MTuWF Monday, Tuesday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Narges Nematollahi', 5, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'In this course, students will examine the classical Persian tradition''s rich legacy of historical, literary, and religious writings. Students will learn the grammatical and lexical differences distinguishing classical from modern Persian, and will be introduced to basic research tools and reference works. Readings cover the range of classical Persian texts.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 755', 'ADVANCED SORANI KURDISH I', '11172', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'HD TBA', 'Hewa Khalid', 9, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Advanced Sorani Kurdish I will help students bring their listening, speaking, reading, and writing to levels appropriate for living and operating in the target-language environment. We will almost entirely use native sources supplemented by worksheets.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 755', 'ADVANCED SORANI KURDISH I', '15212', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Hewa Khalid', 10, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Advanced Sorani Kurdish I will help students bring their listening, speaking, reading, and writing to levels appropriate for living and operating in the target-language environment. We will almost entirely use native sources supplemented by worksheets.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 761', 'ADVANCED MONGOLIAN I', '4518', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'GA 4021', 'Tserenchunt Legden', 1, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Students first review compound and complex sentences and then develop a sense of Mongolian literary style through the reading of diverse materials. In-class oral presentations, discussions, and role-plays help students to increase their fluency. Students are introduced to translation, and their knowledge of Mongolian culture and history is enhanced.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 761', 'ADVANCED MONGOLIAN I', '7934', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Students first review compound and complex sentences and then develop a sense of Mongolian literary style through the reading of diverse materials. In-class oral presentations, discussions, and role-plays help students to increase their fluency. Students are introduced to translation, and their knowledge of Mongolian culture and history is enhanced.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 761', 'ADVANCED MONGOLIAN I', '10703', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'WB WEB', 'Tserenchunt Legden', 4, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Students first review compound and complex sentences and then develop a sense of Mongolian literary style through the reading of diverse materials. In-class oral presentations, discussions, and role-plays help students to increase their fluency. Students are introduced to translation, and their knowledge of Mongolian culture and history is enhanced.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 771', 'ADVANCED TIBETAN I', '6432', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WH 114', 'Gedun Rabsal', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Advanced Tibetan I helps students acquire advanced skills in an academic and professional manner. Students expand their knowledge of grammar with reading and composition exercises, and translate general texts from Tibetan into English. The course will focus on reading in modern and classical Tibetan.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 771', 'ADVANCED TIBETAN I', '7940', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'WB WEB', 'Gedun Rabsal', 5, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Advanced Tibetan I helps students acquire advanced skills in an academic and professional manner. Students expand their knowledge of grammar with reading and composition exercises, and translate general texts from Tibetan into English. The course will focus on reading in modern and classical Tibetan.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 781', 'ADVANCED TURKISH I', '4519', 'Class Status', 'MWF Monday, Wednesday, Friday 8:00 AM–8:50 AM', 'GA 0003', 'Sibel Crum', 5, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Advanced Turkish is based on authentic materials such as watching Turkish TV news via Oncourse, and writing a report on it. All language skills (listening, speaking, reading, and writing) are improved in class activities. At coffee hours students can interact with native speakers in a friendly environment.', ARRAY[]::TEXT[], NULL),
    ('CEUS-T 798', 'ADVANCED CENTRAL EURASIAN LANGUAGES I', '6850', 'Class Status', NULL, NULL, 'Piibi-Kai Kivik', 2, NULL, 'Lecture', '3', 'MARTIN HALL', ARRAY[]::TEXT[], 'This variable titles class is used for fall semester of advanced-level modern language classes which do not yet have their own number. Such languages will be Uralic; Altaic; Iranian; or Tibeto-Burman languages of the Tibetan Plateau-Himalayas region. Students may not use more than one such language for departmental degree requirements.', ARRAY[]::TEXT[], NULL),
