    ('CEUS-T 798', 'ADVANCED CENTRAL EURASIAN LANGUAGES I', '35007', 'Class Status', 'TuTh Tuesday, Thursday 9:00 AM–10:15 AM', 'WB WEB', 'Narges Nematollahi', 1, NULL, 'Lecture', '3', 'MARTIN HALL', ARRAY[]::TEXT[], 'This variable titles class is used for fall semester of advanced-level modern language classes which do not yet have their own number. Such languages will be Uralic; Altaic; Iranian; or Tibeto-Burman languages of the Tibetan Plateau-Himalayas region. Students may not use more than one such language for departmental degree requirements.', ARRAY[]::TEXT[], NULL),
    ('CEUS-X 490', 'ADVANCED READINGS IN CENTRAL EURASIAN STUDIES', '11012', 'Class Status', NULL, NULL, 'Justyna Zajac', 5, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], 'Independent, directed study of an advanced topic in Central Eurasian Studies that covers multiple areas or does not fit comfortably in any specific area. Readings may include work on demanding classical texts or a survey of the secondary literature on a topic.', ARRAY[]::TEXT[], NULL),
